var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"장 볼 것도 별로 없으면서 난 왜 끌고 나온 거야?","JPN":"買うものもないくせになんで妾をつれて来たんだ？","ENG":"Why did you drag me out? The grocery list wasn't even that long.","TWN":"又沒什麼要買的，幹嘛拉我出來？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"바람 좀 쐬라고 부른 거지. 요새 한숨 쉬는 일이 많길래.","JPN":"気晴らしにどうかと思って。最近ため息ついてることが多かったでしょう？","ENG":"I just thought you could use some fresh air. You've been sighing a lot these days.","TWN":"當然是找你出來散散心囉，我看你最近經常唉聲歎氣的。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"뭐가 그렇게 고민인지 얘기라도 꺼내 주면 더 좋고?","JPN":"何をそんなに悩んでいるのか話してくれない？","ENG":"You can tell me what's bothering you, you know?","TWN":"要跟我說說你在煩什麼嗎？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"카페 운영 고민밖에 더 있겠어?","JPN":"妾の悩みといえばカフェの経営のことに決まっているだろう。","ENG":"It's about the cafe, as usual.","TWN":"除了咖啡廳，我還能煩什麼？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그라운드 원에 하도 괴짜들이 많으니까 마녀 컨셉만으로는 좀 부족한 것 같다고 생각하던 참이야.","JPN":"グラウンド・ワンは変人ばかりだから、魔女コンセプトだけでは役不足なんじゃないかと考えていたんだ。","ENG":"There are a lot of freaks in Ground One, and I don't think the witch theme is enough anymore.","TWN":"G1的怪咖有夠多，我覺得光靠魔女的主題好像不夠。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"크하핫! 이 무지한 시민들이여, <color=#ffd34c>블론드 햇 캣</color>님의 연주를 듣고 자선 냄비를 가득 채워라!","JPN":"フハハ！　無知な市民どもよ、<color=#ffd34c>ブロンドハットキャット</color>様の演奏を聞き、この募金箱をパンパンにしろ！","ENG":"Mwa ha ha! Foolish citizens, hear the glorious performance of <color=#ffd34c>Blonde Hat Cat</color> and fill the red kettle up to the brim!","TWN":"哇哈哈！你們這些無知的市民，聽完<color=#ffd34c>金帽貓</color>的演奏後，給我把這個募款箱裝滿！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"잘 모아서 도움이 필요한 곳에 뿌려 버릴 테니까! 크핫핫핫!","JPN":"集まった金は困っているところに寄付してくれようぞ！　フハハハ！","ENG":"I'll force those donations on the people who really need them! Mwa ha ha ha!","TWN":"我會把錢收集起來，扔到需要幫助的地方！哇哈哈哈！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ONLY_C_VIOLET_HYPER_ATTACK"},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"……봤지?","JPN":"……ほらな？","ENG":"...See?","TWN":"……你看吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으음. 뭐 하나 평범한 게 없긴 해.","JPN":"うーん。確かに平凡ではないかも。","ENG":"Mmm. Nothing really is \\"normal.\\"","TWN":"嗯嗯，確實是都怪怪的。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"여긴 균열 때문에 침식 현상도 잦고, 그러다 보니 살기가 꽤 팍팍해서 그럴 지도 모르지.","JPN":"ここは亀裂のせいで侵食現象もよく発生するから、暮らしに余裕がなくてそうなのかもしれないわね。","ENG":"There are frequent Counterside Effects because of the Crevice, so maybe that's made people's lives difficult.","TWN":"這裡因為大峽谷的關係經常發生侵蝕現象，所以日子過得很辛苦吧……？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"게다가 이래저래 사건사고가 끊이지 않는 곳이니까.","JPN":"それに、いろんな事件や事故が絶えず起こっているし。","ENG":"Plus, there's always something going on.","TWN":"而且事件老是一波未平一波又起。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"살기 팍팍해질수록 더 강한 컨셉이 필요한 건가…….","JPN":"暮らしに余裕がなくなればなくなるほど、もっと強烈なコンセプトが必要なんじゃ……","ENG":"The more difficult it is to live, the more extreme the theme has to be... Is that it?","TWN":"生活越辛苦，就越需要更厲害的主題嗎……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CAMERA_NPC_SUPPLEMENT_NULL","text":{"KOREA":"스위트 베이 스튜디오에서 웨딩 촬영 이벤트 진행합니다~","JPN":"スイートベイ・スタジオではウェディングフォトイベントが開催中です～","ENG":"Join us at Sweet Bay Studio for an enchanting wedding picture event!","TWN":"甜蜜港灣工作室正在進行婚紗拍攝活動喔～"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAMERA_NPC_SUPPLEMENT_NULL","text":{"KOREA":"꼭꼭 숨어 계셨던 예비 부부들 모두 얼른 나와서 신청하세요!","JPN":"結婚を控えたカップルの皆さん、お早めにお申し込みください！","ENG":"Engaged couples, this is your chance! Don't miss out! Sign up now!","TWN":"低調的準新人快來報名吧！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAMERA_NPC_SUPPLEMENT_NULL","text":{"KOREA":"더도 말고 덜도 말도 액자 값만 따악 받습니다! 이런 이벤트 또 없어요!","JPN":"価格は写真代のみ、他は頂きません！　こんなイベントもう無いですよ！","ENG":"You'll only have to pay for the frame and nothing else! It's a once-in-a-lifetime event!","TWN":"費用不多也不少，就只收你相框錢！超值活動！絕無僅有！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"웨딩 이벤트?","JPN":"ウェディングイベント？","ENG":"A wedding event?","TWN":"婚禮活動？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"지금 같은 때에? 결혼하는 사람이 얼마나 있다고?","JPN":"このご時世に結婚式を挙げる人がどれだけいるっていうんだ？","ENG":"Now? I doubt there are a lot of people trying to get married.","TWN":"現在這種時候？會有很多人要結婚嗎？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"줄 선 거 보니까 생각보다 꽤 있는 것 같은데?","JPN":"並んでいるところを見ると、意外といるみたいよ？","ENG":"Well, by the looks of that long queue, there might be more than you think.","TWN":"你看那邊排隊的人潮，好像還蠻多的呢？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"……그러게. 아까 살기 팍팍하다는 얘기를 했던 것 같은데.","JPN":"……そのようだな。さっき暮らしに余裕がないとか言ってた気がするが。","ENG":"...Huh. Weren't we talking about how difficult people's lives are?","TWN":"……真的欸，剛才不是才說生活很辛苦嗎？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이때가 아니면 또 영영 미뤄질 수도 있으니까 서두르는 걸 수도 있지.","JPN":"今しないとずっと後回しになる可能性もあるから、急ぐのかもしれないわね。","ENG":"They might be rushing it, since it might be now or never.","TWN":"可能現在不結，以後就沒機會了吧？所以才會這麼著急？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"흐음, 웨딩 이벤트라…….","JPN":"ふうん。ウェディングイベントか……","ENG":"Hmm. A wedding event…","TWN":"嗯，婚禮活動……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"다녀왔어~","JPN":"ただいま～","ENG":"We're back!","TWN":"我們回來囉～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 에블린 언니! 라우라!","JPN":"あ！　エヴリン姉さん！　ラウラ！","ENG":"Oh! Evelyn! Laura!","TWN":"喔！伊芙琳姊姊！蘿拉！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L33_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우리가 카페 청소 다 해 놨어! 오늘은 아무것도 안 깼다구!","JPN":"カフェの掃除しておいたよ！　今日は何も割ってないから！","ENG":"We finished cleaning the cafe! And we didn't break anything today!","TWN":"咖啡廳都打掃完了！我今天沒有打破任何東西喔！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L35_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어… 어어…….","JPN":"え……ええ……","ENG":"Uh... Uhhh...","TWN":"哎呀呀……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이, 이건 억울해!","JPN":"な、なんで！？","ENG":"Th-this is unfair!","TWN":"竟然在最後一刻破功！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"하아. 하루이틀도 아니고. 이제 까일 월급도 없겠어.","JPN":"はあ、またか……もう差し引ける給料も残ってないんじゃないか？","ENG":"*Sigh* Again? I'd say that's coming out of your paycheck, but you have nothing left.","TWN":"哀，每天都打破東西，你的薪水都已經扣完咧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"흐잉…….","JPN":"ふえん……","ENG":"Hngh...","TWN":"嗚嗚……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"걱정 마! 내가 마법으로 싹 치워 줄 테니까!","JPN":"心配ご無用！　私が魔法で全部片づけてあげるよ！","ENG":"Don't worry! I'll use my magic to clean it up!","TWN":"別擔心！我用魔法幫你收拾乾淨！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이 정도면 라우라처럼 손짓 한 방으로……!","JPN":"このくらい、ラウラみたいに手の一振りで……！","ENG":"I'll do what Laura does, just a simple hand gestu–","TWN":"小意思啦，只要像蘿拉一樣動動手指……！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"아! 왜 때려!","JPN":"いてっ！　なんで叩くの！？","ENG":"Aw! Why did you hit me?!","TWN":"唉唷！幹嘛打我！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"마법이 무슨 만능 해결 도구인 줄 알아?","JPN":"魔法をなんでも解決できる道具か何かだと思っているのか？","ENG":"You think magic is some kind of Swiss Army knife?","TWN":"你以為魔法是萬能的嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"남발했다가 무슨 부작용이 생길 지 아무도 모른다고.","JPN":"むやみに使えばどんな副作用があるか、誰にもわからないんだぞ。","ENG":"No one knows what kind of side effects might occur when you overuse it!","TWN":"沒人知道亂用會有什麼副作用。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그럼 마법은 대체 언제 쓰라는 거야…….","JPN":"だったら、魔法をいつ使えっていうんだ……","ENG":"When else am I supposed to use magic...","TWN":"那到底什麼時候才能使用魔法……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"적어도 남발하지는 말라는 거지. 너 같은 애송이는 더더욱 조심해야 하고.","JPN":"少なくともむやみには使うなということだ。汝のような若造はなおさら気を付けなければな。","ENG":"I mean, just don't use it so often. And a rookie like you should be even more careful.","TWN":"至少不能隨便亂用，像你這樣的小屁孩，更要小心。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"쳇.","JPN":"ちっ。","ENG":"Tch.","TWN":"嘖。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"치우는 건 에블린에게 맡기고, 너희 둘은 심부름 좀 다녀와.","JPN":"片づけるのはエヴリンに任せて、二人はお使いに行ってきてくれ。","ENG":"Leave Evelyn to clean this up. You two can go run an errand.","TWN":"交給伊芙琳收拾吧，你們二個去幫忙買點東西回來。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"카페에 장식해 둘 웨딩 소품을 사야 하거든.","JPN":"カフェを飾るウェディンググッズを買わないといけないからな。","ENG":"We need wedding props for the cafe.","TWN":"我要買一些裝飾咖啡廳的婚禮用品。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"웨딩 소품?","JPN":"ウェディンググッズ？","ENG":"Wedding props?","TWN":"婚禮用品？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"웨딩 이벤트를 열 거야. 마침 시기도 적절하고.","JPN":"ウェディングイベントをするんだ。時期的にもちょうどいい。","ENG":"We're going to host a wedding-themed event. It's a good time to do it.","TWN":"我想弄個婚禮主題的活動，現在時機剛剛好。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"……손님들도 끌어올 겸.","JPN":"……お客さんを呼び込むことも兼ねてな。","ENG":"...And we need more customers.","TWN":"……也順便招攬客人。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"웨딩 이벤트! 말만 들어도 엄청 재밌을 것 같아!","JPN":"ウェディングイベント！　すごく面白そうだね！","ENG":"A wedding-themed event?! Sounds like tons of fun!","TWN":"婚禮活動！一聽就覺得很有意思！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"당장 다녀올게! 가자, 유나야!","JPN":"すぐ行ってくる！　行こう、ユナ！","ENG":"We'll leave right now! Let's go, Yuna!","TWN":"我們立刻去辦！走吧，尤娜！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"응!","JPN":"うん！","ENG":"Okay!","TWN":"嗯！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"웨딩 이벤트면… 생각해 둔 컨셉이라도 있어?","JPN":"ウェディングイベントっていうと……何かコンセプトでも考えてあるの？","ENG":"A wedding-themed event... Do you have any ideas in mind?","TWN":"婚禮主題的活動……你有什麼想法嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그걸 이제 생각해야지.","JPN":"それはこれから考えないとな。","ENG":"That's what I have to do now.","TWN":"當然是現在才要想囉。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"새로운 디저트를 만들어 볼까? 웨딩 컨셉에 맞게 화려한 느낌으로.","JPN":"新しいデザートでも作ってみようかしら？　ウェディングコンセプトに合うように華やかな感じで。","ENG":"Should we come up with a new dessert? Something exquisite that would fit the wedding theme.","TWN":"推出一些新的甜點怎麼樣？搭配婚禮主題，做得華麗一些。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그런 걸로 경쟁이 되겠어?","JPN":"そんなので他の店に勝てるのか？","ENG":"That's not going to be enough.","TWN":"這樣有競爭力嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"적어도 웨딩 디저트에 특별한 마법을 걸거나……","JPN":"少なくてもウェディングデザートに特別な魔法をかけるとか……","ENG":"At the very least, we should cast a spell on the wedding desserts...","TWN":"起碼也在婚禮甜點上加點特別的魔法……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"웨딩 드레스 정도는 만들어 입어 주는 게 명목상 좋을 것 같은데.","JPN":"ウェディングドレスを作って着るとかした方がいいんじゃないか。","ENG":"Or, make and wear wedding dresses.","TWN":"或是做一件婚紗穿上也蠻符合主題的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"웨딩 드레스?","JPN":"ウェディングドレス？","ENG":"Wedding dresses?","TWN":"婚紗？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그래도 옷 잘 짓는다고 소문난 카페인데, 그 정도는 해야 하지 않을까?","JPN":"一応服作りで有名なカフェなんだから、そのくらいは必要なんじゃないか？","ENG":"I feel like we should, since we're known for our costume-creating skills, after all.","TWN":"我們咖啡廳不是以訂製服出名的嗎？婚紗至少要做一下吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"애들 오면 옷 만드는 것부터 당장 시작하라고 해.","JPN":"二人が帰ってきたら、すぐにドレス作りに取り掛かるように言ってくれ。","ENG":"When the two come back, have them start making the costumes immediately.","TWN":"等她們回來，就叫她們立刻開始製作。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 새로운 웨딩 디저트 연구는 내가, 디저트에 걸 특별한 마법은 네가 준비하면 되겠다.","JPN":"じゃあ、新しいウェディングデザートの研究は私が、デザートにかける特別な魔法はあなたが用意すればいいわね。","ENG":"Then I'll do the research for the new wedding-themed desserts, and you can prepare the spell for it.","TWN":"那我來研究新的婚禮甜點，你來負責要加在甜點上的特別魔法囉。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"연인끼리 함께 먹으면 사이가 더 좋아진다거나 하는 식이면 좋겠네.","JPN":"恋人同士で食べると仲が良くなる、みたいなのがいいわ。","ENG":"It would be nice if it were to, for example, strengthen your relationship if you ate it with your lover.","TWN":"像是情侶一起吃下去後感情會升溫的魔法之類的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"흐음.","JPN":"ふうん。","ENG":"Hmm.","TWN":"嗯哼。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아니면 프로포즈할 용기를 갖게 해주는 마법도 괜찮고.","JPN":"プロポーズする勇気を出させてくれる、っていうのもいいわね。","ENG":"Or a spell that gives you the courage to propose.","TWN":"或是會讓人有勇氣求婚的魔法也不錯。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"……뭐. 일단은 알겠어. 한번 고민해 볼게.","JPN":"……とりあえず、わかった。考えてみる。","ENG":"...Well, all right. I'll think about it.","TWN":"……嗯，我知道了，我再想想看。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};